import React from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import AuctionList from "./pages/AuctionList";
import CreateRFQ from "./pages/CreateRFQ";
import AuctionDetail from "./pages/AuctionDetail";

const Navbar = () => {
  return (
    <nav className="w-full bg-[#1e3a5f] text-white shadow-md">
      <div className="mx-auto flex h-16 max-w-7xl items-center justify-between px-4 sm:px-6 lg:px-8">
        <Link to="/" className="text-base font-bold sm:text-lg">
          British Auction - RFQ System
        </Link>
        <div className="flex items-center gap-2 sm:gap-3">
          <Link
            to="/"
            className="rounded-md px-3 py-2 text-sm font-medium hover:bg-white/10"
          >
            All Auctions
          </Link>
          <Link
            to="/create-rfq"
            className="rounded-md bg-[#2563eb] px-3 py-2 text-sm font-semibold text-white hover:bg-blue-700"
          >
            Create RFQ
          </Link>
        </div>
      </div>
    </nav>
  );
};

const App = () => {
  return (
    <Router>
      <Navbar />
      <main className="min-h-screen bg-[#f1f5f9]">
        <Routes>
          <Route path="/" element={<AuctionList />} />
          <Route path="/create" element={<CreateRFQ />} />
          <Route path="/create-rfq" element={<CreateRFQ />} />
          <Route path="/rfq/:id" element={<AuctionDetail />} />
        </Routes>
      </main>
    </Router>
  );
};

export default App;
